mapper.sql:
WHERE s.member_id = #{memberId}
  AND s.deleted_at IS NULL

  AND s.name LIKE CONCAT('%', #{keyword}, '%')


  AND s.category_id = #{categoryId}


  AND s.status = #{status}



  AND DATEDIFF(s.next_payment_date, CURDATE()) >= 8


  AND DATEDIFF(s.next_payment_date, CURDATE()) BETWEEN 1 AND 7


  AND DATEDIFF(s.next_payment_date, CURDATE()) = 0


  AND DATEDIFF(s.next_payment_date, CURDATE()) < 0

mapper.select:
SELECT
FROM subscription s INNER JOIN subscription_category c ON s.category_id = c.category_id
ORDER BY s.next_payment_date ASC, s.subscription_id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE subscription
SET deleted_at = NOW(6)
WHERE subscription_id = #{subscriptionId}
  AND member_id = #{memberId}
  AND deleted_at IS NULL
